import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Read the whole line

        // Limit the input length to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input is too long. Please enter a name with 10 characters or less.");
            return;
        }

        char[] buffer = new char[10];
        name.getChars(0, Math.min(name.length(), 10), buffer, 0); // Copy up to 10 characters

        System.out.println("Hello, " + new String(buffer).trim()); // Trim any extra spaces

        // Properly handle resources
        scanner.close();
    }
}

